create table utenti_tlg.tbl_anag_imprese (
    id_impresa         number(38, 0) not null enable,
    cod_impresa        number(38, 0),
    nome_impresa       varchar2(100 byte),
    referente          varchar2(50 byte),
    indirizzo          varchar2(100 byte),
    comune             varchar2(50 byte),
    cap                char(5 byte),
    p_iva              varchar2(11 byte),
    cod_fiscale        char(16 byte),
    data_fine_validita date,
    tipo_impresa       char(1 byte),
    alias_zbx          varchar2(30 byte)
);


